// Serve the admin dashboard HTML
const html = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Framed - Admin Dashboard</title>
    <style>
        /* CSS from admin-dashboard.html */
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto; background: #1a1a1a; color: #fff; line-height: 1.6; }
        .container { max-width: 1200px; margin: 0 auto; padding: 20px; }
        .header { text-align: center; margin-bottom: 40px; padding: 20px; background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); border-radius: 12px; }
        .header h1 { font-size: 2.5rem; margin-bottom: 10px; }
        .stats-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 20px; margin-bottom: 30px; }
        .stat-card { background: #2a2a2a; padding: 30px; border-radius: 12px; text-align: center; }
        .stat-value { font-size: 2.5rem; font-weight: bold; color: #667eea; }
        .subscribers-table { background: #2a2a2a; border-radius: 12px; overflow: hidden; }
        table { width: 100%; border-collapse: collapse; }
        th, td { padding: 15px; text-align: left; border-bottom: 1px solid #3a3a3a; }
        .tier-badge { padding: 4px 12px; border-radius: 20px; font-weight: 600; }
        .tier-framed { background: #667eea; color: white; }
        .tier-framed-plus { background: #764ba2; color: white; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>🖼️ Framed Admin Dashboard</h1>
            <p>Live Subscription Data</p>
        </div>
        <div class="stats-grid">
            <div class="stat-card"><div class="stat-value" id="totalSubs">Loading...</div><div>Total Subscribers</div></div>
            <div class="stat-card"><div class="stat-value" id="activeSubs">Loading...</div><div>Active Subscriptions</div></div>
            <div class="stat-card"><div class="stat-value" id="revenue">Loading...</div><div>Monthly Revenue</div></div>
        </div>
        <div class="subscribers-table">
            <table>
                <thead><tr><th>Username</th><th>Tier</th><th>Status</th><th>Date</th></tr></thead>
                <tbody id="data">Loading...</tbody>
            </table>
        </div>
    </div>
    <script>
        fetch('/webhook/framed-admin-data')
            .then(r => r.json())
            .then(data => {
                document.getElementById('totalSubs').textContent = data.stats.total;
                document.getElementById('activeSubs').textContent = data.stats.active;
                document.getElementById('revenue').textContent = '$' + data.stats.revenue;
                document.getElementById('data').innerHTML = data.subscribers.map(s => 
                    \`<tr><td>@\${s.username}</td><td><span class="tier-badge tier-\${s.tier.replace('+','-plus')}">\${s.tier}</span></td><td>\${s.active ? '✓ Active' : '✗ Inactive'}</td><td>\${s.date}</td></tr>\`
                ).join('');
            });
    </script>
</body>
</html>`;

return [{
  json: {},
  binary: {
    data: {
      data: Buffer.from(html, 'utf8'),
      mimeType: 'text/html'
    }
  }
}];

// Process subscriber data and calculate stats
const subscribers = [];
let totalSubs = 0;
let activeSubs = 0;
let framedCount = 0;
let framedPlusCount = 0;

// Process each row from Google Sheets
for (const item of $input.all()) {
  const data = item.json;

  // Skip header row
  if (data.username === 'username' || !data.username) continue;

  const isActive = data.active === true || data.active === 'true' || data.active === 'TRUE';
  const tier = (data.tier || '').toLowerCase();

  totalSubs++;

  if (isActive) {
    activeSubs++;
    if (tier === 'framed') framedCount++;
    if (tier === 'framed+') framedPlusCount++;
  }

  subscribers.push({
    username: data.username || 'Unknown',
    chatId: data.chat_id || data.chatId || 'N/A',
    tier: tier || 'framed',
    active: isActive,
    date: data.subscribed_date || data.subscribedDate || 'Unknown',
    stripeCustomer: data.stripe_customer_id || data.stripeCustomerId || 'N/A'
  });
}

// Calculate revenue
const monthlyRevenue = (framedCount * 4.99) + (framedPlusCount * 9.99);

// Return formatted data
return [{
  json: {
    stats: {
      total: totalSubs,
      active: activeSubs,
      framed: framedCount,
      framedPlus: framedPlusCount,
      revenue: monthlyRevenue.toFixed(2)
    },
    subscribers: subscribers
      .sort((a, b) => new Date(b.date) - new Date(a.date)) // Sort by most recent
      .slice(0, 50) // Limit to 50 most recent
  }
}];

const query = $json.query || {};
const tier = (query.tier || '').toLowerCase();
const requestedDate = query.date || '';

if (tier !== 'framed+') {
  return [{ json: { error: 'Framed+ subscription required for archive access.' } }];
}

const archiveRows = [
  { date: '2026-04-17', category: 'anime', title: 'Sample title', caption: 'Sample caption', drive_url: 'https://drive.example/sample', telegram_url: '' }
];

const filtered = requestedDate ? archiveRows.filter(row => row.date === requestedDate) : archiveRows.slice(0, 14);

return [{ json: { archive: filtered, count: filtered.length, statusCode: tier === 'framed+' ? 200 : 403 } }];
